                        error={startDateError}
                      />
                    </div>
                    {showTimeInput && (
                      <Input
                        size="small"
                        value={startTime}
                        onChange={(value) => setStartTime(value)}
                        error={startTimeError}
                      />
                    )}
                  </div>
                </div>
                <div>
