                    onClick={onApply}
                  >
                    Apply
                  </Button>
                </div>
                <div className="w-fit self-center">
                  <Select
                    size="xsmall"
                    variant="ghost"
                    options={timezones}
                    value={selectedTimezone}
                    onChange={(event) => setSelectedTimezone(event.target.value)}
                  />
                </div>
              </div>
            </div>
          </div>
        </Material>
      )}
    </div>
  );
};

