      setCurrentPreset(array[presetIndex][1]);
      onChange({ start: array[presetIndex][1].start, end: array[presetIndex][1].end });
    }
  }, [presetIndex]);

  useEffect(() => {
    if (currentPreset) {
      if (currentPreset.start !== value?.start || currentPreset.end !== value?.end) {
        setCurrentPreset(null);
        setInputValue("");
      }
