        value={inputValue}
        onChange={onChangeInputValue}
        wrapperClassName={clsx(
          "hover:z-10",
          stacked && !compact && "rounded-b-none",
          !stacked && !compact && "rounded-r-none",
          compact && "rounded-l-none",
