        )}
        className={clsx(
          "pl-2 placeholder:!text-gray-1000 placeholder:!opacity-100",
          compact && !isOpen && (!currentPreset || (currentPreset?.start !== value?.start && currentPreset?.end !== value?.end)) && "!w-0 !px-0"
